import React, { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react';
import { BrowserRouter, Routes, Route, Link, useNavigate, useParams, Outlet, useLocation } from 'react-router-dom';
import { LogIn, UserPlus, Building, PlusCircle, House, MapPin, Search, Edit, Trash2, MessageSquare, Heart, LayoutDashboard, Bell } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, RadialBarChart, RadialBar } from 'recharts';
import api from './api';

// --- AUTHENTICATION CONTEXT ---
const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
    const [currentUser, setCurrentUser] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        try {
            const storedUser = localStorage.getItem("currentUser");
            if (storedUser) setCurrentUser(JSON.parse(storedUser));
        } catch (error) {
            console.error("Failed to parse stored user", error);
            localStorage.clear();
        }
        setLoading(false);
    }, []);

    useEffect(() => {
        if (currentUser) {
            localStorage.setItem("currentUser", JSON.stringify(currentUser));
        } else {
            localStorage.removeItem("currentUser");
            localStorage.removeItem("token");
        }
    }, [currentUser]);

    const logout = useCallback(() => setCurrentUser(null), []);

    return (
        <AuthContext.Provider value={{ currentUser, setCurrentUser, logout, loading }}>
            {!loading && children}
        </AuthContext.Provider>
    );
};

export const useAuth = () => useContext(AuthContext);

// --- DASHBOARD LAYOUT & COMPONENTS ---

const DashboardLayout = () => {
    const { currentUser } = useAuth();
    const navigate = useNavigate();

    useEffect(() => {
        if (!currentUser) {
            navigate('/login');
        }
    }, [currentUser, navigate]);

    if (!currentUser) {
        return null; // or a loading spinner
    }

    return (
        <div className="flex h-screen bg-slate-900 text-slate-100 font-sans">
            <Sidebar />
            <div className="flex-1 flex flex-col overflow-hidden">
                <Header />
                <main className="flex-1 overflow-x-hidden overflow-y-auto bg-slate-900 p-8">
                    <Outlet />
                </main>
            </div>
        </div>
    );
};

const Sidebar = () => {
    const location = useLocation();
    const { currentUser, logout } = useAuth();
    const navigate = useNavigate();

    const handleLogout = () => {
        logout();
        navigate('/login');
    };
    
    const navItems = [
        { icon: LayoutDashboard, label: "Dashboard", path: "/" },
        { icon: Building, label: "Properties", path: "/properties" },
        { icon: MessageSquare, label: "Messages", path: "/messages" },
        { icon: Heart, label: "Favorites", path: "/favorites" },
    ];

    return (
        <aside className="w-64 bg-slate-900 p-6 flex flex-col border-r border-slate-800">
            <div className="flex items-center space-x-2 mb-10">
                <Building className="h-8 w-8 text-indigo-400" />
                <span className="text-white text-2xl font-bold">Housing Hub</span>
            </div>
            <nav className="flex-1">
                <ul>
                    {navItems.map(item => (
                        <li key={item.label}>
                            <Link to={item.path} className={`flex items-center gap-3 px-4 py-3 my-2 rounded-lg transition-colors ${location.pathname.startsWith(item.path) && item.path !== '/' || location.pathname === '/' && item.path === '/' ? 'bg-indigo-600 text-white' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                                <item.icon size={20} />
                                <span>{item.label}</span>
                            </Link>
                        </li>
                    ))}
                </ul>
            </nav>
            <div className="mt-auto">
                {currentUser && (
                    <div className="flex items-center gap-3 p-3 bg-slate-800 rounded-lg mb-4">
                        <img className="h-10 w-10 rounded-full object-cover" src={`https://placehold.co/100x100/1e293b/a78bfa?text=${currentUser.email.charAt(0).toUpperCase()}`} alt="User Avatar" />
                        <div>
                            <p className="font-semibold text-white truncate">{currentUser.email}</p>
                            <p className="text-sm text-slate-400 capitalize">{currentUser.userType}</p>
                        </div>
                    </div>
                )}
                 <button onClick={handleLogout} className="w-full flex items-center justify-center gap-2 text-slate-400 hover:bg-red-900/50 hover:text-white py-2 rounded-lg transition-colors">
                    <LogIn size={16} />
                    <span>Logout</span>
                </button>
            </div>
        </aside>
    );
};

const Header = () => {
    const location = useLocation();
    const getTitle = () => {
        if (location.pathname.startsWith('/properties/')) return 'Property Details';
        switch (location.pathname) {
            case '/': return 'Dashboard';
            case '/properties': return 'Property Listings';
            case '/add-property': return 'Add New Property';
            case '/messages': return 'Your Messages';
            case '/favorites': return 'My Favorites';
            default: return 'Housing Hub';
        }
    };
    
    return (
        <header className="bg-slate-900/80 backdrop-blur-md p-4 flex justify-between items-center border-b border-slate-800 flex-shrink-0">
            <div>
                 <h1 className="text-2xl font-bold text-white">{getTitle()}</h1>
            </div>
            <div className="flex items-center gap-4">
                <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
                    <input type="text" placeholder="Search..." className="bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500" />
                </div>
                <button className="p-2 bg-slate-800 rounded-lg border border-slate-700 hover:bg-slate-700">
                    <Bell size={20} className="text-slate-300" />
                </button>
                {useAuth().currentUser?.userType === 'landlord' && (
                    <Link to="/add-property" className="bg-indigo-600 text-white font-bold py-2 px-4 rounded-lg flex items-center gap-2 hover:bg-indigo-500 transition-colors">
                        <PlusCircle size={20} />
                        <span>New Property</span>
                    </Link>
                )}
            </div>
        </header>
    );
};

// --- PAGE COMPONENTS (VIEWS) ---

const DashboardView = () => {
    const propertyListenData = [ { name: 'Jan', uv: 400, pv: 2400 }, { name: 'Feb', uv: 300, pv: 1398 }, { name: 'Mar', uv: 200, pv: 9800 }, { name: 'Apr', uv: 278, pv: 3908 }, { name: 'May', uv: 189, pv: 4800 }, { name: 'Jun', uv: 239, pv: 3800 }, { name: 'Jul', uv: 349, pv: 4300 }, ];
    const radialChartData = [{ name: 'Occupancy', uv: 50, fill: '#818cf8' }];

    return (
        <div className="space-y-8">
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 bg-slate-800/50 p-6 rounded-2xl border border-slate-700">
                    <h2 className="text-xl font-bold text-white mb-4">Featured Property</h2>
                    <div className="bg-cover bg-center p-6 rounded-lg h-64 flex flex-col justify-end" style={{ backgroundImage: "url('https://images.unsplash.com/photo-1580587771525-78b9dba3b914?q=80&w=2574&auto=format&fit=crop')" }}>
                        <div className="bg-black/50 backdrop-blur-sm p-4 rounded-md">
                            <h3 className="text-lg font-semibold text-white">Modern Villa with Pool</h3>
                            <p className="text-sm text-slate-300">123 Luxury Ave, Miami, FL</p>
                        </div>
                    </div>
                </div>
                <div className="bg-slate-800/50 p-6 rounded-2xl border border-slate-700 space-y-4">
                     <h2 className="text-xl font-bold text-white mb-2">Recent Listings</h2>
                     <div className="flex items-center gap-4 p-3 bg-slate-700/50 rounded-lg">
                        <img src="https://images.unsplash.com/photo-1560448204-e02f11c3d0e2?q=80&w=2670&auto=format&fit=crop" alt="Property" className="w-24 h-16 rounded-md object-cover" />
                        <div>
                            <p className="font-semibold text-white">Downtown Loft</p>
                            <p className="text-indigo-400 font-bold">$4,500<span className="text-sm text-slate-400 font-normal">/mo</span></p>
                        </div>
                     </div>
                     <div className="flex items-center gap-4 p-3 bg-slate-700/50 rounded-lg">
                        <img src="https://images.unsplash.com/photo-1448630360428-65456885c650?q=80&w=2667&auto=format&fit=crop" alt="Property" className="w-24 h-16 rounded-md object-cover" />
                        <div>
                            <p className="font-semibold text-white">Suburban House</p>
                            <p className="text-indigo-400 font-bold">$3,200<span className="text-sm text-slate-400 font-normal">/mo</span></p>
                        </div>
                     </div>
                </div>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 bg-slate-800/50 p-6 rounded-2xl border border-slate-700">
                    <h2 className="text-xl font-bold text-white mb-4">Property Views Analytics</h2>
                     <ResponsiveContainer width="100%" height={250}>
                        <BarChart data={propertyListenData}>
                            <CartesianGrid strokeDasharray="3 3" stroke="#374151" />
                            <XAxis dataKey="name" stroke="#9ca3af" />
                            <YAxis stroke="#9ca3af" />
                            <Tooltip contentStyle={{ backgroundColor: '#1f2937', border: '1px solid #374151' }} cursor={{fill: 'rgba(129, 140, 248, 0.1)'}}/>
                            <Bar dataKey="pv" fill="#818cf8" />
                        </BarChart>
                    </ResponsiveContainer>
                </div>
                <div className="bg-slate-800/50 p-6 rounded-2xl border border-slate-700 flex flex-col items-center justify-center">
                    <h2 className="text-xl font-bold text-white mb-4">Occupancy Rate</h2>
                    <ResponsiveContainer width="100%" height={250}>
                         <RadialBarChart innerRadius="70%" outerRadius="90%" data={radialChartData} startAngle={90} endAngle={-270} barSize={30}>
                            <RadialBar minAngle={15} dataKey='uv' cornerRadius={15} />
                            <text x="50%" y="50%" textAnchor="middle" dominantBaseline="middle" className="text-4xl font-bold fill-white">50%</text>
                         </RadialBarChart>
                    </ResponsiveContainer>
                </div>
            </div>
        </div>
    );
};

const PropertiesView = () => {
    const { currentUser } = useAuth();
    const [properties, setProperties] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    const fetchProperties = useCallback(async () => {
        setLoading(true);
        try {
            const response = await api.get('/api/properties');
            setProperties(response.data);
        } catch (err) {
            setError('Failed to fetch properties.');
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchProperties();
    }, [fetchProperties]);

    const handleDelete = async (propertyId) => {
        if (window.confirm('Are you sure you want to delete this property?')) {
            try {
                await api.delete(`/api/properties/${propertyId}`);
                fetchProperties();
            } catch (err) {
                alert('Failed to delete property.');
            }
        }
    };

    if (loading) return <div className="text-center text-slate-400">Loading properties...</div>;
    if (error) return <div className="text-center text-red-400">{error}</div>;

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {properties.map(prop => (
                <div key={prop._id} className="bg-slate-800/50 rounded-2xl shadow-lg border border-slate-700 overflow-hidden group">
                    <div className="overflow-hidden h-56">
                      <img src={prop.image_url || 'https://placehold.co/400x300/1e293b/94a3b8?text=No+Image'} alt={prop.title} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"/>
                    </div>
                    <div className="p-6">
                        <h3 className="text-xl font-bold text-white mb-2 truncate">{prop.title}</h3>
                        <p className="text-slate-400 text-sm mb-4 flex items-center gap-2"><MapPin size={16} />{prop.address}, {prop.city}</p>
                        <div className="flex justify-between items-center">
                            <p className="text-indigo-400 text-2xl font-bold">₹{prop.price.toLocaleString()}<span className="text-sm text-slate-400 font-normal">/mo</span></p>
                            {currentUser.userType === 'landlord' && currentUser.uid === prop.landlord_id && (
                                <div className="flex items-center gap-2">
                                    <button className="p-2 bg-slate-700 rounded-md hover:bg-indigo-600 transition-colors"><Edit size={16} /></button>
                                    <button onClick={() => handleDelete(prop._id)} className="p-2 bg-slate-700 rounded-md hover:bg-red-600 transition-colors"><Trash2 size={16} /></button>
                                </div>
                            )}
                             {currentUser.userType === 'student' && (
                                <button className="p-2 bg-slate-700 rounded-md hover:bg-pink-600 transition-colors"><Heart size={16} /></button>
                             )}
                        </div>
                    </div>
                </div>
            ))}
        </div>
    );
};

const AddPropertyView = () => {
    const navigate = useNavigate();
    const [details, setDetails] = useState({ title: '', description: '', address: '', city: '', price: '', property_type: 'apartment', bedrooms: '', bathrooms: '', amenities: '' });
    const [images, setImages] = useState([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const [message, setMessage] = useState('');

    const handleChange = (e) => setDetails({ ...details, [e.target.name]: e.target.value });
    const handleImageChange = (e) => setImages(e.target.files);

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError('');
        setMessage('');

        const formData = new FormData();
        Object.keys(details).forEach(key => formData.append(key, details[key]));
        for (let i = 0; i < images.length; i++) {
            formData.append('images', images[i]);
        }

        try {
            // Explicitly set the Content-Type header for this request
            await api.post('/api/properties', formData, {
                headers: {
                    'Content-Type': 'multipart/form-data',
                },
            });
            setMessage('Property added successfully! Redirecting...');
            setTimeout(() => navigate('/properties'), 2000);
        } catch (err) {
            setError(err.response?.data?.message || 'Failed to add property. Please check the console for more details.');
            console.error(err); // Log the full error to the console for debugging
        } finally {
            setLoading(false);
        }
    };
    
    return (
        <div className="bg-slate-800/50 p-8 rounded-2xl border border-slate-700 max-w-4xl mx-auto">
            {error && <div className="bg-red-900/50 border border-red-700 text-red-300 p-3 rounded-lg mb-6">{error}</div>}
            {message && <div className="bg-green-900/50 border border-green-700 text-green-300 p-3 rounded-lg mb-6">{message}</div>}
            <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="md:col-span-2">
                    <label className="block text-sm font-medium text-slate-300 mb-1">Property Title</label>
                    <input name="title" required value={details.title} onChange={handleChange} className="w-full bg-slate-900 border border-slate-600 rounded-lg p-2.5 text-white focus:ring-indigo-500 focus:border-indigo-500"/>
                </div>
                <div>
                    <label className="block text-sm font-medium text-slate-300 mb-1">Address</label>
                    <input name="address" required value={details.address} onChange={handleChange} className="w-full bg-slate-900 border border-slate-600 rounded-lg p-2.5 text-white focus:ring-indigo-500 focus:border-indigo-500"/>
                </div>
                <div>
                    <label className="block text-sm font-medium text-slate-300 mb-1">City</label>
                    <input name="city" required value={details.city} onChange={handleChange} className="w-full bg-slate-900 border border-slate-600 rounded-lg p-2.5 text-white focus:ring-indigo-500 focus:border-indigo-500"/>
                </div>
                 <div>
                    <label className="block text-sm font-medium text-slate-300 mb-1">Price (per month)</label>
                    <input name="price" type="number" required value={details.price} onChange={handleChange} className="w-full bg-slate-900 border border-slate-600 rounded-lg p-2.5 text-white focus:ring-indigo-500 focus:border-indigo-500"/>
                </div>
                <div>
                    <label className="block text-sm font-medium text-slate-300 mb-1">Property Type</label>
                    <select name="property_type" value={details.property_type} onChange={handleChange} className="w-full bg-slate-900 border border-slate-600 rounded-lg p-2.5 text-white focus:ring-indigo-500 focus:border-indigo-500">
                        <option value="apartment">Apartment</option>
                        <option value="house">House</option>
                        <option value="room">Room</option>
                    </select>
                </div>
                <div>
                    <label className="block text-sm font-medium text-slate-300 mb-1">Bedrooms</label>
                    <input name="bedrooms" type="number" value={details.bedrooms} onChange={handleChange} className="w-full bg-slate-900 border border-slate-600 rounded-lg p-2.5 text-white focus:ring-indigo-500 focus:border-indigo-500"/>
                </div>
                 <div>
                    <label className="block text-sm font-medium text-slate-300 mb-1">Bathrooms</label>
                    <input name="bathrooms" type="number" value={details.bathrooms} onChange={handleChange} className="w-full bg-slate-900 border border-slate-600 rounded-lg p-2.5 text-white focus:ring-indigo-500 focus:border-indigo-500"/>
                </div>
                <div className="md:col-span-2">
                    <label className="block text-sm font-medium text-slate-300 mb-1">Description</label>
                    <textarea name="description" rows="4" value={details.description} onChange={handleChange} className="w-full bg-slate-900 border border-slate-600 rounded-lg p-2.5 text-white focus:ring-indigo-500 focus:border-indigo-500"></textarea>
                </div>
                <div className="md:col-span-2">
                    <label className="block text-sm font-medium text-slate-300 mb-1">Amenities (comma-separated)</label>
                    <input name="amenities" value={details.amenities} onChange={handleChange} className="w-full bg-slate-900 border border-slate-600 rounded-lg p-2.5 text-white focus:ring-indigo-500 focus:border-indigo-500"/>
                </div>
                <div className="md:col-span-2">
                    <label className="block text-sm font-medium text-slate-300 mb-1">Images (up to 5)</label>
                    <input type="file" name="images" onChange={handleImageChange} className="w-full text-slate-400 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-indigo-600 file:text-white hover:file:bg-indigo-500 cursor-pointer" multiple/>
                </div>
                <div className="md:col-span-2 mt-4">
                    <button type="submit" disabled={loading} className="w-full bg-indigo-600 text-white py-3 rounded-lg font-semibold hover:bg-indigo-500 transition disabled:bg-indigo-800 disabled:cursor-not-allowed">
                        {loading ? 'Submitting...' : 'Add Property'}
                    </button>
                </div>
            </form>
        </div>
    );
};


// --- AUTHENTICATION PAGES ---

const AuthForm = ({ isLogin }) => {
    const { setCurrentUser } = useAuth();
    const navigate = useNavigate();
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [userType, setUserType] = useState('student');
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');
        if (!isLogin && password !== confirmPassword) {
            return setError('Passwords do not match');
        }
        setLoading(true);
        const endpoint = isLogin ? '/api/login' : '/api/signup';
        const payload = isLogin ? { email, password } : { email, password, userType };
        try {
            const response = await api.post(endpoint, payload);
            const data = response.data;
            const userToStore = { email: data.email, uid: data.userId, userType: data.userType };
            setCurrentUser(userToStore);
            localStorage.setItem("token", data.token);
            navigate("/");
        } catch (err) {
            setError(err.response?.data?.message || 'An unexpected error occurred.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-slate-900 p-4">
            <div className="max-w-md w-full bg-slate-800/60 backdrop-blur-sm border border-slate-700 shadow-2xl shadow-indigo-900/50 rounded-2xl p-8">
                <h2 className="text-3xl font-extrabold text-center text-white mb-6">{isLogin ? 'Login to Housing Hub' : 'Create Your Account'}</h2>
                {error && (<div className="bg-red-900/50 border border-red-700 text-red-300 px-4 py-3 rounded-xl mb-4 text-center">{error}</div>)}
                <form className="space-y-6" onSubmit={handleSubmit}>
                    <div>
                        <label htmlFor="email" className="block text-sm font-medium text-slate-300">Email address</label>
                        <input id="email" type="email" required value={email} onChange={(e) => setEmail(e.target.value)} className="mt-1 block w-full px-4 py-2 bg-slate-900 border border-slate-600 rounded-lg shadow-sm text-white focus:ring-indigo-500 focus:border-indigo-500" placeholder="your@email.com" />
                    </div>
                    <div>
                        <label htmlFor="password" className="block text-sm font-medium text-slate-300">Password</label>
                        <input id="password" type="password" required value={password} onChange={(e) => setPassword(e.target.value)} className="mt-1 block w-full px-4 py-2 bg-slate-900 border border-slate-600 rounded-lg shadow-sm text-white focus:ring-indigo-500 focus:border-indigo-500" placeholder="••••••••" />
                    </div>
                    {!isLogin && (
                        <>
                            <div>
                                <label htmlFor="confirmPassword" className="block text-sm font-medium text-slate-300">Confirm Password</label>
                                <input id="confirmPassword" type="password" required value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} className="mt-1 block w-full px-4 py-2 bg-slate-900 border border-slate-600 rounded-lg shadow-sm text-white focus:ring-indigo-500 focus:border-indigo-500" placeholder="••••••••" />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-300 mb-2">I am a:</label>
                                <div className="flex space-x-2 bg-slate-900 p-1 rounded-lg">
                                    <label className={`w-1/2 text-center p-2 rounded-md cursor-pointer transition-colors ${userType === 'student' ? 'bg-indigo-600 text-white' : 'text-slate-300 hover:bg-slate-700'}`}>
                                        <input type="radio" className="sr-only" name="userType" value="student" checked={userType === 'student'} onChange={() => setUserType('student')} />Student
                                    </label>
                                    <label className={`w-1/2 text-center p-2 rounded-md cursor-pointer transition-colors ${userType === 'landlord' ? 'bg-indigo-600 text-white' : 'text-slate-300 hover:bg-slate-700'}`}>
                                        <input type="radio" className="sr-only" name="userType" value="landlord" checked={userType === 'landlord'} onChange={() => setUserType('landlord')} />Landlord
                                    </label>
                                </div>
                            </div>
                        </>
                    )}
                    <button type="submit" disabled={loading} className="w-full bg-indigo-600 text-white py-2.5 rounded-lg hover:bg-indigo-500 transition disabled:bg-indigo-800 disabled:cursor-not-allowed font-semibold">{loading ? "Processing..." : (isLogin ? "Login" : "Sign Up")}</button>
                </form>
                <p className="mt-6 text-center text-sm text-slate-400">
                    {isLogin ? "Don't have an account? " : "Already have an account? "}
                    <Link to={isLogin ? "/signup" : "/login"} className="text-indigo-400 hover:text-indigo-300 font-semibold">{isLogin ? "Sign Up" : "Login"}</Link>
                </p>
            </div>
        </div>
    );
};


// --- MAIN APP ROUTER ---
export default function App() {
    return (
        <AuthProvider>
            <BrowserRouter>
                <Routes>
                    <Route path="/" element={<DashboardLayout />}>
                        <Route index element={<DashboardView />} />
                        <Route path="properties" element={<PropertiesView />} />
                        <Route path="add-property" element={<AddPropertyView />} />
                    </Route>
                    <Route path="/login" element={<AuthForm isLogin />} />
                    <Route path="/signup" element={<AuthForm isLogin={false} />} />
                </Routes>
            </BrowserRouter>
        </AuthProvider>
    );
}
